import prompts from 'prompts';
import chalk from 'chalk';
import logger from '../utils/logger.js';

/**
 * ApprovalManager - Manages user approval for tool executions
 * 
 * Responsibilities:
 * - Determine if tool execution requires approval
 * - Prompt user for approval when needed
 * - Track autonomy mode settings
 * - Identify dangerous operations
 * - Maintain approval history
 */
class ApprovalManager {
  /**
   * Create a new ApprovalManager
   * @param {Object} config - Configuration object
   * @param {TerminalInterface} terminalInterface - Terminal interface instance
   * @param {Object} options - Additional options
   */
  constructor(config, terminalInterface, options = {}) {
    if (!config) {
      throw new Error('Configuration is required');
    }

    if (!terminalInterface) {
      throw new Error('TerminalInterface is required');
    }

    this.config = config;
    this.terminal = terminalInterface;
    this.options = options;

    // Get agent configuration
    this.agentConfig = config.agent || {};
    
    // Set default autonomy mode
    this.autonomyMode = this.agentConfig.autonomyMode || 'safe';
    
    // Auto-approved tools list
    this.autoApproveTools = new Set(this.agentConfig.autoApproveTools || []);
    
    // Enhanced dangerous commands patterns
    this.dangerousCommands = this.agentConfig.dangerousCommands || [
      'rm -rf',
      'sudo',
      'chmod',
      'chown',
      'mkfs',
      'dd',
      'format',
      'del /f',
      'rmdir /s',
      'format c:',
      'fdisk',
      'parted',
      'killall',
      'pkill',
      'systemctl',
      'service',
      'reboot',
      'shutdown',
      'halt',
      'poweroff'
    ];

    // Safety limits and guardrails
    this.safetyLimits = {
      maxFileSize: this.agentConfig.maxFileSize || 10 * 1024 * 1024, // 10MB
      maxFilesPerBatch: this.agentConfig.maxFilesPerBatch || 50,
      maxCommandLength: this.agentConfig.maxCommandLength || 1000,
      maxToolCallsPerMinute: this.agentConfig.maxToolCallsPerMinute || 30,
      blockedPaths: this.agentConfig.blockedPaths || [
        '/etc',
        '/bin',
        '/sbin',
        '/usr/bin',
        '/usr/sbin',
        '/boot',
        '/sys',
        '/proc',
        'C:\\Windows',
        'C:\\Program Files',
        'C:\\System32'
      ],
      blockedExtensions: this.agentConfig.blockedExtensions || [
        '.exe',
        '.dll',
        '.sys',
        '.bat',
        '.cmd',
        '.ps1',
        '.sh',
        '.bash'
      ]
    };

    // Rate limiting for tool calls
    this.toolCallHistory = [];
    this.rateLimitWindow = 60000; // 1 minute in milliseconds

    // Approval history
    this.approvalHistory = [];

    // Undo/redo capability
    this.undoStack = [];
    this.redoStack = [];
    this.maxUndoStackSize = 50;

    // Define autonomy mode rules
    this.autonomyRules = {
      safe: {
        autoApprove: ['read_file', 'list_directory', 'search_code'],
        requireApproval: ['write_file', 'replace_in_file', 'execute_command', 'create_directory', 'create_multiple_files']
      },
      autonomous: {
        autoApprove: ['read_file', 'list_directory', 'search_code', 'write_file', 'replace_in_file', 'create_directory', 'create_multiple_files'],
        requireApproval: ['execute_command']
      },
      full: {
        autoApprove: ['read_file', 'list_directory', 'search_code', 'write_file', 'replace_in_file', 'create_directory', 'create_multiple_files', 'execute_command'],
        requireApproval: [] // Only dangerous commands require approval
      }
    };
  }

  /**
   * Request approval for tool execution with enhanced safety checks
   * @param {string} toolName - Name of the tool to execute
   * @param {Object} parameters - Tool parameters
   * @returns {Promise<boolean>} True if approved, false if denied
   */
  async requestApproval(toolName, parameters = {}) {
    if (!toolName || typeof toolName !== 'string') {
      throw new Error('Tool name must be a non-empty string');
    }

    logger.debug('Requesting approval for tool', { toolName, parameters });

    // Check rate limiting first
    if (!this._checkRateLimit()) {
      this.terminal.displayError('Rate limit exceeded. Too many tool calls in the last minute.');
      this._recordApproval(toolName, parameters, false, 'rate-limited');
      return false;
    }

    // Validate tool parameters
    const validationResult = this._validateToolParameters(toolName, parameters);
    if (!validationResult.valid) {
      this.terminal.displayError(`Tool validation failed: ${validationResult.reason}`);
      this._recordApproval(toolName, parameters, false, 'validation-failed');
      return false;
    }

    // Check if tool is auto-approved
    if (this.isAutoApproved(toolName, parameters)) {
      logger.debug('Tool auto-approved', { toolName });
      this._recordApproval(toolName, parameters, true, 'auto-approved');
      this._recordToolCall(toolName);
      return true;
    }

    // Check if operation is dangerous
    const dangerous = this.isDangerous(toolName, parameters);
    
    // Display tool call information
    this._displayToolCallInfo(toolName, parameters, dangerous);

    try {
      // Prompt user for approval
      const response = await prompts({
        type: 'confirm',
        name: 'approved',
        message: dangerous 
          ? chalk.red.bold('⚠️  This is a potentially dangerous operation. Do you want to proceed?')
          : chalk.yellow('Do you want to execute this tool?'),
        initial: !dangerous // Default to true for non-dangerous operations
      });

      // Handle Ctrl+C or cancelled prompt
      if (response.approved === undefined) {
        logger.info('Tool approval cancelled by user', { toolName });
        this._recordApproval(toolName, parameters, false, 'cancelled');
        return false;
      }

      const approved = response.approved;
      const reason = approved ? 'user-approved' : 'user-denied';
      
      logger.info('Tool approval decision', { toolName, approved, reason });
      this._recordApproval(toolName, parameters, approved, reason);

      if (approved) {
        this._recordToolCall(toolName);
        this.terminal.displaySuccess(`Tool "${toolName}" approved for execution`);
        
        // Create undo point for file operations
        if (this._isFileOperation(toolName)) {
          this._createUndoPoint(toolName, parameters);
        }
      } else {
        this.terminal.displayWarning(`Tool "${toolName}" execution denied`);
      }

      return approved;

    } catch (error) {
      logger.error('Error during approval request', { toolName, error: error.message });
      this._recordApproval(toolName, parameters, false, 'error');
      return false;
    }
  }

  /**
   * Check if a tool is auto-approved based on current autonomy mode
   * @param {string} toolName - Name of the tool
   * @param {Object} parameters - Tool parameters
   * @returns {boolean} True if auto-approved
   */
  isAutoApproved(toolName, parameters = {}) {
    // Check if tool is in explicit auto-approve list
    if (this.autoApproveTools.has(toolName)) {
      return true;
    }

    // Check if operation is dangerous (never auto-approve dangerous operations)
    if (this.isDangerous(toolName, parameters)) {
      return false;
    }

    // Check autonomy mode rules
    const rules = this.autonomyRules[this.autonomyMode];
    if (!rules) {
      logger.warn('Unknown autonomy mode, defaulting to safe mode', { mode: this.autonomyMode });
      return this.autonomyRules.safe.autoApprove.includes(toolName);
    }

    return rules.autoApprove.includes(toolName);
  }

  /**
   * Check if a tool operation is dangerous with enhanced detection
   * @param {string} toolName - Name of the tool
   * @param {Object} parameters - Tool parameters
   * @returns {boolean} True if dangerous
   */
  isDangerous(toolName, parameters = {}) {
    // Check for dangerous command execution
    if (toolName === 'execute_command' && parameters.command) {
      const command = parameters.command.toLowerCase().trim();
      
      // Check against dangerous command patterns
      for (const dangerousPattern of this.dangerousCommands) {
        if (command.includes(dangerousPattern.toLowerCase())) {
          return true;
        }
      }

      // Enhanced dangerous patterns
      const dangerousPatterns = [
        /rm\s+.*-r.*\//,           // rm with recursive and root-like paths
        /sudo\s+/,                 // sudo commands
        /chmod\s+.*777/,           // chmod 777
        />\s*\/dev\/null/,         // Redirecting to /dev/null (potential data loss)
        /mkfs\./,                  // File system creation
        /fdisk/,                   // Disk partitioning
        /dd\s+.*of=/,              // dd command with output file
        /curl.*\|\s*sh/,           // Piping curl to shell
        /wget.*\|\s*sh/,           // Piping wget to shell
        /eval\s*\(/,               // eval commands
        /exec\s*\(/,               // exec commands
        /system\s*\(/,             // system calls
        /\|\s*bash/,               // Piping to bash
        /\|\s*sh/,                 // Piping to shell
        />\s*\/etc\//,             // Writing to /etc
        />\s*\/bin\//,             // Writing to /bin
        />\s*\/usr\/bin\//,        // Writing to /usr/bin
        /crontab\s+-/,             // Crontab modifications
        /iptables/,                // Firewall modifications
        /ufw\s+/,                  // UFW firewall
        /firewall-cmd/,            // Firewall commands
        /passwd\s+/,               // Password changes
        /usermod\s+/,              // User modifications
        /userdel\s+/,              // User deletion
        /groupdel\s+/,             // Group deletion
        /mount\s+/,                // Mounting filesystems
        /umount\s+/,               // Unmounting filesystems
        /scp\s+.*root@/,           // SCP to root
        /ssh\s+.*root@/,           // SSH as root
        /rsync.*--delete/          // Rsync with delete
      ];

      for (const pattern of dangerousPatterns) {
        if (pattern.test(command)) {
          return true;
        }
      }

      // Check command length
      if (command.length > this.safetyLimits.maxCommandLength) {
        return true;
      }
    }

    // Enhanced dangerous file operations
    if (toolName === 'write_file' || toolName === 'replace_in_file') {
      const filePath = parameters.path || '';
      
      // Check against blocked paths
      for (const blockedPath of this.safetyLimits.blockedPaths) {
        if (filePath.startsWith(blockedPath)) {
          return true;
        }
      }

      // Check against blocked extensions
      const extension = filePath.split('.').pop()?.toLowerCase();
      if (extension && this.safetyLimits.blockedExtensions.includes(`.${extension}`)) {
        return true;
      }

      // Check for important configuration files
      const dangerousFiles = [
        'package.json',
        'package-lock.json',
        'yarn.lock',
        '.env',
        '.env.local',
        '.env.production',
        '.gitignore',
        '.gitattributes',
        'Dockerfile',
        'docker-compose.yml',
        'docker-compose.yaml',
        'Makefile',
        'CMakeLists.txt',
        'requirements.txt',
        'Pipfile',
        'Gemfile',
        'composer.json',
        'pom.xml',
        'build.gradle',
        'Cargo.toml',
        'go.mod',
        'tsconfig.json',
        'webpack.config.js',
        'vite.config.js',
        'rollup.config.js',
        '.babelrc',
        '.eslintrc',
        '.prettierrc',
        'jest.config.js',
        'vitest.config.js'
      ];

      const fileName = filePath.split('/').pop() || filePath.split('\\').pop();
      if (dangerousFiles.includes(fileName)) {
        return true;
      }
    }

    // Enhanced batch file creation checks
    if (toolName === 'create_multiple_files' && parameters.files) {
      const fileCount = Array.isArray(parameters.files) ? parameters.files.length : 0;
      if (fileCount > this.safetyLimits.maxFilesPerBatch) {
        return true;
      }

      // Check if any individual file in the batch is dangerous
      if (Array.isArray(parameters.files)) {
        for (const file of parameters.files) {
          if (this.isDangerous('write_file', { path: file.path })) {
            return true;
          }
        }
      }
    }

    // Check file size limits
    if ((toolName === 'write_file' || toolName === 'create_multiple_files') && parameters.content) {
      const contentSize = typeof parameters.content === 'string' 
        ? parameters.content.length 
        : JSON.stringify(parameters.content).length;
      
      if (contentSize > this.safetyLimits.maxFileSize) {
        return true;
      }
    }

    return false;
  }

  /**
   * Set the autonomy mode
   * @param {string} mode - Autonomy mode ('safe', 'autonomous', 'full')
   * @returns {boolean} True if mode was set successfully
   */
  setAutonomyMode(mode) {
    const validModes = ['safe', 'autonomous', 'full'];
    
    if (!validModes.includes(mode)) {
      throw new Error(`Invalid autonomy mode: ${mode}. Valid modes: ${validModes.join(', ')}`);
    }

    const previousMode = this.autonomyMode;
    this.autonomyMode = mode;

    // Update configuration
    if (this.config.agent) {
      this.config.agent.autonomyMode = mode;
    }

    logger.info('Autonomy mode changed', { previousMode, newMode: mode });
    
    this.terminal.displaySuccess(`Autonomy mode changed from "${previousMode}" to "${mode}"`);
    this._displayAutonomyModeInfo(mode);

    return true;
  }

  /**
   * Get the current autonomy mode
   * @returns {string} Current autonomy mode
   */
  getAutonomyMode() {
    return this.autonomyMode;
  }

  /**
   * Add a tool to the auto-approve list
   * @param {string} toolName - Name of the tool to auto-approve
   */
  addAutoApprovalTool(toolName) {
    if (!toolName || typeof toolName !== 'string') {
      throw new Error('Tool name must be a non-empty string');
    }

    this.autoApproveTools.add(toolName);
    
    // Update configuration
    if (this.config.agent) {
      this.config.agent.autoApproveTools = Array.from(this.autoApproveTools);
    }

    logger.info('Tool added to auto-approve list', { toolName });
    this.terminal.displaySuccess(`Tool "${toolName}" added to auto-approve list`);
  }

  /**
   * Remove a tool from the auto-approve list
   * @param {string} toolName - Name of the tool to remove from auto-approve
   */
  removeAutoApprovalTool(toolName) {
    if (!toolName || typeof toolName !== 'string') {
      throw new Error('Tool name must be a non-empty string');
    }

    const removed = this.autoApproveTools.delete(toolName);
    
    if (removed) {
      // Update configuration
      if (this.config.agent) {
        this.config.agent.autoApproveTools = Array.from(this.autoApproveTools);
      }

      logger.info('Tool removed from auto-approve list', { toolName });
      this.terminal.displaySuccess(`Tool "${toolName}" removed from auto-approve list`);
    } else {
      this.terminal.displayWarning(`Tool "${toolName}" was not in auto-approve list`);
    }
  }

  /**
   * Get approval history
   * @param {number} limit - Maximum number of entries to return
   * @returns {Array} Array of approval history entries
   */
  getApprovalHistory(limit = 50) {
    return this.approvalHistory.slice(-limit);
  }

  /**
   * Clear approval history
   */
  clearApprovalHistory() {
    this.approvalHistory = [];
    logger.info('Approval history cleared');
    this.terminal.displaySuccess('Approval history cleared');
  }

  /**
   * Handle mode command - change autonomy mode via command
   * @param {string} mode - New autonomy mode
   * @returns {boolean} True if mode was changed successfully
   */
  handleModeCommand(mode) {
    if (!mode) {
      // Display current mode info
      this._displayAutonomyModeInfo();
      return true;
    }

    try {
      this.setAutonomyMode(mode);
      return true;
    } catch (error) {
      this.terminal.displayError(`Failed to set autonomy mode: ${error.message}`);
      return false;
    }
  }

  /**
   * Get approval statistics
   * @returns {Object} Statistics about approvals
   */
  getApprovalStats() {
    const stats = {
      total: this.approvalHistory.length,
      approved: 0,
      denied: 0,
      autoApproved: 0,
      cancelled: 0,
      errors: 0,
      toolStats: {}
    };

    this.approvalHistory.forEach(entry => {
      switch (entry.reason) {
        case 'user-approved':
          stats.approved++;
          break;
        case 'user-denied':
          stats.denied++;
          break;
        case 'auto-approved':
          stats.autoApproved++;
          break;
        case 'cancelled':
          stats.cancelled++;
          break;
        case 'error':
          stats.errors++;
          break;
      }

      // Track per-tool statistics
      if (!stats.toolStats[entry.toolName]) {
        stats.toolStats[entry.toolName] = {
          total: 0,
          approved: 0,
          denied: 0
        };
      }

      stats.toolStats[entry.toolName].total++;
      if (entry.approved) {
        stats.toolStats[entry.toolName].approved++;
      } else {
        stats.toolStats[entry.toolName].denied++;
      }
    });

    return stats;
  }

  /**
   * Display current autonomy mode information
   * @param {string} mode - Autonomy mode to display info for
   * @private
   */
  _displayAutonomyModeInfo(mode = this.autonomyMode) {
    const rules = this.autonomyRules[mode];
    if (!rules) return;

    console.log(chalk.bold.cyan(`\n📋 Autonomy Mode: ${mode.toUpperCase()}\n`));
    
    if (rules.autoApprove.length > 0) {
      console.log(chalk.green('✓ Auto-approved tools:'));
      rules.autoApprove.forEach(tool => {
        console.log(chalk.green(`  • ${tool}`));
      });
    }

    if (rules.requireApproval.length > 0) {
      console.log(chalk.yellow('\n⚠ Requires approval:'));
      rules.requireApproval.forEach(tool => {
        console.log(chalk.yellow(`  • ${tool}`));
      });
    }

    console.log(chalk.red('\n🚫 Always requires approval:'));
    console.log(chalk.red('  • Dangerous operations (rm -rf, sudo, etc.)'));
    console.log('');
  }

  /**
   * Display tool call information to user
   * @param {string} toolName - Name of the tool
   * @param {Object} parameters - Tool parameters
   * @param {boolean} dangerous - Whether the operation is dangerous
   * @private
   */
  _displayToolCallInfo(toolName, parameters, dangerous) {
    // Create visual separator
    const borderChar = dangerous ? '═' : '─';
    const borderColor = dangerous ? chalk.red.bold : chalk.yellow.bold;
    
    console.log(borderColor(`\n╭${borderChar.repeat(58)}╮`));
    
    // Header with appropriate icon and color
    const icon = dangerous ? '⚠️ ' : '🔧 ';
    const headerText = dangerous ? 'DANGEROUS TOOL EXECUTION REQUEST' : 'TOOL EXECUTION REQUEST';
    const headerColor = dangerous ? chalk.red.bold : chalk.yellow.bold;
    
    console.log(borderColor('│') + headerColor(` ${icon}${headerText}`.padEnd(58)) + borderColor('│'));
    console.log(borderColor(`╰${borderChar.repeat(58)}╯`));
    
    // Tool name with appropriate styling
    const toolColor = dangerous ? chalk.red.bold : chalk.cyan.bold;
    console.log(`\n${toolColor('Tool:')} ${chalk.white(toolName)}`);
    
    // Display parameters with better formatting
    if (parameters && Object.keys(parameters).length > 0) {
      console.log(chalk.bold.white('\nParameters:'));
      Object.entries(parameters).forEach(([key, value]) => {
        let displayValue = value;
        
        // Format different parameter types
        if (typeof value === 'string') {
          if (value.length > 200) {
            displayValue = value.substring(0, 200) + chalk.gray('... [truncated]');
          }
          // Highlight file paths
          if (key === 'path' || key === 'filePath' || key.includes('Path')) {
            displayValue = chalk.cyan(displayValue);
          }
          // Highlight commands
          else if (key === 'command') {
            displayValue = chalk.yellow(displayValue);
          }
        } else if (typeof value === 'object') {
          displayValue = JSON.stringify(value, null, 2);
          if (displayValue.length > 200) {
            displayValue = displayValue.substring(0, 200) + chalk.gray('... [truncated]');
          }
        } else if (typeof value === 'boolean') {
          displayValue = value ? chalk.green('true') : chalk.red('false');
        }
        
        console.log(chalk.white(`  ${key}: `) + chalk.gray(displayValue));
      });
    }

    // Display danger warning with enhanced styling
    if (dangerous) {
      console.log(chalk.red.bold('\n╔══════════════════════════════════════════════════════════╗'));
      console.log(chalk.red.bold('║') + chalk.red.bold('  ⚠️  WARNING: POTENTIALLY DANGEROUS OPERATION  ⚠️   ').padEnd(58) + chalk.red.bold('║'));
      console.log(chalk.red.bold('╚══════════════════════════════════════════════════════════╝'));
      console.log(chalk.red('This operation could modify system files, execute commands,'));
      console.log(chalk.red('or perform other actions that might affect your system.'));
    }

    console.log('');
  }

  /**
   * Check rate limiting for tool calls
   * @returns {boolean} True if within rate limit
   * @private
   */
  _checkRateLimit() {
    const now = Date.now();
    const windowStart = now - this.rateLimitWindow;
    
    // Remove old entries
    this.toolCallHistory = this.toolCallHistory.filter(timestamp => timestamp > windowStart);
    
    // Check if we're within the limit
    return this.toolCallHistory.length < this.safetyLimits.maxToolCallsPerMinute;
  }

  /**
   * Record a tool call for rate limiting
   * @param {string} toolName - Name of the tool
   * @private
   */
  _recordToolCall(toolName) {
    this.toolCallHistory.push(Date.now());
    logger.debug('Tool call recorded for rate limiting', { toolName, count: this.toolCallHistory.length });
  }

  /**
   * Validate tool parameters against safety limits
   * @param {string} toolName - Name of the tool
   * @param {Object} parameters - Tool parameters
   * @returns {Object} Validation result
   * @private
   */
  _validateToolParameters(toolName, parameters) {
    // Validate file paths
    if (parameters.path) {
      const path = parameters.path;
      
      // Check for path traversal attempts
      if (path.includes('..') || path.includes('~')) {
        return { valid: false, reason: 'Path traversal detected in file path' };
      }
      
      // Check for null bytes
      if (path.includes('\0')) {
        return { valid: false, reason: 'Null byte detected in file path' };
      }
      
      // Check path length
      if (path.length > 500) {
        return { valid: false, reason: 'File path too long' };
      }
    }

    // Validate command parameters
    if (toolName === 'execute_command' && parameters.command) {
      const command = parameters.command;
      
      // Check for command injection attempts
      const injectionPatterns = [
        /;\s*rm/,
        /&&\s*rm/,
        /\|\s*rm/,
        /`.*`/,
        /\$\(/,
        /\${/
      ];
      
      for (const pattern of injectionPatterns) {
        if (pattern.test(command)) {
          return { valid: false, reason: 'Potential command injection detected' };
        }
      }
    }

    // Validate file content size
    if (parameters.content) {
      const contentSize = typeof parameters.content === 'string' 
        ? parameters.content.length 
        : JSON.stringify(parameters.content).length;
      
      if (contentSize > this.safetyLimits.maxFileSize) {
        return { 
          valid: false, 
          reason: `Content size (${Math.round(contentSize / 1024)}KB) exceeds limit (${Math.round(this.safetyLimits.maxFileSize / 1024)}KB)` 
        };
      }
    }

    // Validate batch file operations
    if (toolName === 'create_multiple_files' && parameters.files) {
      if (!Array.isArray(parameters.files)) {
        return { valid: false, reason: 'Files parameter must be an array' };
      }
      
      if (parameters.files.length > this.safetyLimits.maxFilesPerBatch) {
        return { 
          valid: false, 
          reason: `Too many files (${parameters.files.length}), limit is ${this.safetyLimits.maxFilesPerBatch}` 
        };
      }
    }

    return { valid: true };
  }

  /**
   * Check if a tool is a file operation
   * @param {string} toolName - Name of the tool
   * @returns {boolean} True if it's a file operation
   * @private
   */
  _isFileOperation(toolName) {
    const fileOperations = ['write_file', 'replace_in_file', 'create_directory', 'create_multiple_files'];
    return fileOperations.includes(toolName);
  }

  /**
   * Create an undo point for file operations
   * @param {string} toolName - Name of the tool
   * @param {Object} parameters - Tool parameters
   * @private
   */
  _createUndoPoint(toolName, parameters) {
    const undoPoint = {
      toolName,
      parameters: { ...parameters },
      timestamp: new Date(),
      id: Date.now().toString()
    };

    this.undoStack.push(undoPoint);

    // Keep undo stack size manageable
    if (this.undoStack.length > this.maxUndoStackSize) {
      this.undoStack.shift();
    }

    // Clear redo stack when new operation is performed
    this.redoStack = [];

    logger.debug('Undo point created', { toolName, undoId: undoPoint.id });
  }

  /**
   * Undo the last file operation
   * @returns {Promise<boolean>} True if undo was successful
   */
  async undoLastOperation() {
    if (this.undoStack.length === 0) {
      this.terminal.displayWarning('No operations to undo');
      return false;
    }

    const lastOperation = this.undoStack.pop();
    
    try {
      // Move to redo stack
      this.redoStack.push(lastOperation);

      this.terminal.displaySuccess(`Undid operation: ${lastOperation.toolName} (${lastOperation.timestamp.toLocaleTimeString()})`);
      logger.info('Operation undone', { toolName: lastOperation.toolName, undoId: lastOperation.id });
      
      return true;
    } catch (error) {
      // Put it back if undo failed
      this.undoStack.push(lastOperation);
      this.terminal.displayError(`Failed to undo operation: ${error.message}`);
      return false;
    }
  }

  /**
   * Redo the last undone operation
   * @returns {Promise<boolean>} True if redo was successful
   */
  async redoLastOperation() {
    if (this.redoStack.length === 0) {
      this.terminal.displayWarning('No operations to redo');
      return false;
    }

    const lastUndone = this.redoStack.pop();
    
    try {
      // Move back to undo stack
      this.undoStack.push(lastUndone);

      this.terminal.displaySuccess(`Redid operation: ${lastUndone.toolName} (${lastUndone.timestamp.toLocaleTimeString()})`);
      logger.info('Operation redone', { toolName: lastUndone.toolName, undoId: lastUndone.id });
      
      return true;
    } catch (error) {
      // Put it back if redo failed
      this.redoStack.push(lastUndone);
      this.terminal.displayError(`Failed to redo operation: ${error.message}`);
      return false;
    }
  }

  /**
   * Get undo/redo history
   * @returns {Object} Undo and redo stacks
   */
  getUndoRedoHistory() {
    return {
      undoStack: this.undoStack.map(op => ({
        toolName: op.toolName,
        timestamp: op.timestamp,
        id: op.id
      })),
      redoStack: this.redoStack.map(op => ({
        toolName: op.toolName,
        timestamp: op.timestamp,
        id: op.id
      }))
    };
  }

  /**
   * Clear undo/redo history
   */
  clearUndoRedoHistory() {
    this.undoStack = [];
    this.redoStack = [];
    this.terminal.displaySuccess('Undo/redo history cleared');
  }

  /**
   * Get current safety limits
   * @returns {Object} Current safety limits
   */
  getSafetyLimits() {
    return { ...this.safetyLimits };
  }

  /**
   * Update safety limits
   * @param {Object} newLimits - New safety limits
   */
  updateSafetyLimits(newLimits) {
    this.safetyLimits = { ...this.safetyLimits, ...newLimits };
    
    // Update configuration
    if (this.config.agent) {
      this.config.agent = { ...this.config.agent, ...newLimits };
    }

    this.terminal.displaySuccess('Safety limits updated');
    logger.info('Safety limits updated', newLimits);
  }

  /**
   * Get rate limiting status
   * @returns {Object} Rate limiting information
   */
  getRateLimitStatus() {
    const now = Date.now();
    const windowStart = now - this.rateLimitWindow;
    const recentCalls = this.toolCallHistory.filter(timestamp => timestamp > windowStart);
    
    return {
      currentCalls: recentCalls.length,
      maxCalls: this.safetyLimits.maxToolCallsPerMinute,
      windowStart: new Date(windowStart),
      windowEnd: new Date(now),
      remaining: Math.max(0, this.safetyLimits.maxToolCallsPerMinute - recentCalls.length)
    };
  }

  /**
   * Record an approval decision in history
   * @param {string} toolName - Name of the tool
   * @param {Object} parameters - Tool parameters
   * @param {boolean} approved - Whether it was approved
   * @param {string} reason - Reason for the decision
   * @private
   */
  _recordApproval(toolName, parameters, approved, reason) {
    const entry = {
      toolName,
      parameters: { ...parameters },
      approved,
      reason,
      timestamp: new Date(),
      autonomyMode: this.autonomyMode
    };

    this.approvalHistory.push(entry);

    // Keep history size manageable
    if (this.approvalHistory.length > 1000) {
      this.approvalHistory = this.approvalHistory.slice(-500);
    }

    logger.debug('Approval decision recorded', entry);
  }
}

export default ApprovalManager;